#!/usr/bin/env python3"""Agent Self-Heal Module v1.0.0"""__version__ = '1.0.0'import jsonimport refrom pathlib import PathERROR_TYPES = {    'powershell_regex': {        'severity': 'medium',        'recoverable': True,        'fix_actions': ['escape_dollar_sign', 'log_and_skip'],        'max_retries': 2,        'description': 'PowerShell regex error'    },    'unknown': {        'severity': 'medium',        'recoverable': True,        'fix_actions': ['log_and_skip'],        'max_retries': 1,        'description': 'Unknown error'    }}def classify_error(error_message):    error_lower = error_message.lower()    if 'regex' in error_lower:        return 'powershell_regex'    return 'unknown'def fix_powershell_regex(error_message, context=None):    return False, None, 'no_fix_available'class SelfHeal:    def __init__(self, team_id, agent_id, workspace=None):        self.team_id = team_id        self.agent_id = agent_id        self.workspace = workspace or Path(__file__).parent.parent.parent / 'shared' / 'team-brain'        self.error_dir = self.workspace / 'errors' / team_id / agent_id        self.error_dir.mkdir(parents=True, exist_ok=True)        self.retries = {}        self.fix_stats = {'success': 0, 'failed': 0, 'skipped': 0}    def handle_error(self, error_message, error_type=None, context=None):        if error_type is None:            error_type = classify_error(error_message)        error_info = ERROR_TYPES.get(error_type, ERROR_TYPES['unknown'])        max_retries = error_info['max_retries']        current_retries = self.retries.get(error_type, 0)        result = {            'error_type': error_type,            'error_message': error_message[:200],            'severity': error_info['severity'],            'retries': current_retries,            'max_retries': max_retries,            'handled': False,            'fix_success': False,            'fix_action': None,            'should_continue': True,            'error_logged': False        }        if current_retries >= max_retries:            result['should_continue'] = False            result['fix_action'] = 'max_retries_exceeded'            self._log_error(error_type, error_message, result)            result['error_logged'] = True            return result        if error_type == 'powershell_regex':            fix_success, fixed_value, fix_action = fix_powershell_regex(error_message, context)            result['fix_success'] = fix_success            result['fix_action'] = fix_action            if fix_success:                self.fix_stats['success'] += 1                self.retries[error_type] = current_retries + 1                result['handled'] = True            else:                self.fix_stats['skipped'] += 1                result['fix_action'] = 'log_and_skip'                result['should_continue'] = False        else:            result['fix_action'] = 'log_and_skip'            result['should_continue'] = False            self.fix_stats['failed'] += 1        self._log_error(error_type, error_message, result)        result['error_logged'] = True        return result    def _log_error(self, error_type, error_message, result):        from datetime import datetime        timestamp = datetime.now().strftime('%Y%m%d-%H%M%S')        log_file = self.error_dir / f'{timestamp}-{error_type}.json'        log_entry = {            'team_id': self.team_id,            'agent_id': self.agent_id,            'timestamp': datetime.now().isoformat(),            'error_type': error_type,            'error_message': error_message,            'result': {                'fix_success': result['fix_success'],                'fix_action': result['fix_action'],                'retries': result['retries'],                'should_continue': result['should_continue']            },            'fix_stats': self.fix_stats.copy()        }        with open(log_file, 'w', encoding='utf-8') as f:            json.dump(log_entry, f, ensure_ascii=False, indent=2)    def get_error_summary(self):        errors = []        for log_file in self.error_dir.glob('*.json'):            with open(log_file, encoding='utf-8') as f:                errors.append(json.load(f))        summary = {'total_errors': len(errors), 'by_type': {}, 'fix_stats': self.fix_stats.copy()}        for e in errors:            et = e['error_type']            summary['by_type'][et] = summary['by_type'].get(et, 0) + 1        return summary    def should_restart_agent(self):        total = self.fix_stats['success'] + self.fix_stats['failed'] + self.fix_stats['skipped']        if total == 0:            return False        return self.fix_stats['failed'] / total > 0.5def main():    import sys    if len(sys.argv) < 2:        print(__doc__)        sys.exit(1)    cmd = sys.argv[1]    if cmd == 'test':        healer = SelfHeal('test-team', 'test-agent')        test_cases = [            'Variable not found: $price',            'Regex argument not valid: [0-9]+',            'PowerShell syntax error at position 5'        ]        for err in test_cases:            print('')            print('Test error: ' + err)            result = healer.handle_error(err)            print('Classification: ' + result['error_type'])            print('Fix: ' + str(result['fix_action']))            print('Continue: ' + str(result['should_continue']))    elif cmd == 'summary':        team_id = sys.argv[2] if len(sys.argv) > 2 else ''        agent_id = sys.argv[3] if len(sys.argv) > 3 else ''        if not team_id or not agent_id:            print('Need team_id and agent_id')            sys.exit(1)        healer = SelfHeal(team_id, agent_id)        summary = healer.get_error_summary()        print(json.dumps(summary, ensure_ascii=False, indent=2))if __name__ == '__main__':    main()